logger = logging.getLogger(__name__)
UserModel = get_user_model()

class SAMLResponseHandler(View):
    @method_decorator(csrf_exempt)
    @method_decorator(require_POST)
    def post(self, request):
        try:
            saml_response = request.POST.get('SAMLResponse')
            if not saml_response:
                return HttpResponse("Missing SAMLResponse", status=400)
            
            # Decode SAML response
            decoded_response = base64.b64decode(saml_response)
            
            # Validate XML structure
            if not self._validate_xml_structure(decoded_response):
                return HttpResponse("Invalid SAML XML structure", status=400)
            
            # Parse SAML assertion
            assertion_data = self._parse_assertion(decoded_response)
            if not assertion_data:
                return HttpResponse("Failed to parse SAML assertion", status=400)
            
            # Create or update user
            user = self._create_or_update_user(assertion_data)
            if not user:
                return HttpResponse("Failed to create/update user", status=400)
            
            # Login user
            login(request, user)
            
            # Redirect to portal
            return HttpResponseRedirect(getattr(settings, 'SAML_REDIRECT_URL', '/'))
            
        except Exception as e:
            logger.error(f"SAML response handling error: {str(e)}")
            return HttpResponse("SAML processing error", status=500)
    
    def _validate_xml_structure(self, xml_data):
        try:
            root = ET.fromstring(xml_data)
            # Check for required elements
            if root.tag != '{urn:oasis:names:tc:SAML:2.0:protocol}Response':
                return False
            
            # Validate assertion structure
            assertions = root.findall('.//{urn:oasis:names:tc:SAML:2.0:assertion}Assertion')
            if not assertions:
                return False
            
            return True
        except ET.ParseError:
            return False
    
    def _parse_assertion(self, xml_data):
        try:
            root = ET.fromstring(xml_data)
            assertion = root.find('.//{urn:oasis:names:tc:SAML:2.0:assertion}Assertion')
            if assertion is None:
                return None
            
            # Extract NameID
            name_id_element = assertion.find('.//{urn:oasis:names:tc:SAML:2.0:assertion}NameID')
            name_id = name_id_element.text if name_id_element is not None else None
            
            # Extract attributes
            attributes = {}
            attribute_statements = assertion.findall('.//{urn:oasis:names:tc:SAML:2.0:assertion}AttributeStatement')
            
            for attr_statement in attribute_statements:
                for attr in attr_statement.findall('.//{urn:oasis:names:tc:SAML:2.0:assertion}Attribute'):
                    attr_name = attr.get('Name')
                    if attr_name:
                        values = [v.text for v in attr.findall('.//{urn:oasis:names:tc:SAML:2.0:assertion}AttributeValue')]
                        attributes[attr_name] = values[0] if values else None
            
            return {
                'name_id': name_id,
                'attributes': attributes
            }
        except Exception as e:
            logger.error(f"Error parsing assertion: {str(e)}")
            return None
    
    def _create_or_update_user(self, assertion_data):
        try:
            name_id = assertion_data.get('name_id')
            attributes = assertion_data.get('attributes', {})
            
            if not name_id:
                return None
            
            # Get or create user based on NameID
            user, created = UserModel.objects.get_or_create(
                username=name_id,
                defaults={
                    'email': attributes.get('email', ''),
                    'first_name': attributes.get('givenName', ''),
                    'last_name': attributes.get('sn', ''),
                }
            )
            
            if not created:
                # Update existing user
                user.email = attributes.get('email', user.email)
                user.first_name = attributes.get('givenName', user.first_name)
                user.last_name = attributes.get('sn', user.last_name)
                user.save()
            
            # Handle groups/roles
            groups = attributes.get('groups', [])
            if groups:
                for group_name in groups:
                    group, _ = Group.objects.get_or_create(name=group_name)
                    user.groups.add(group)
            
            return user
        except Exception as e:
            logger.error(f"Error creating/updating user: {str(e)}")
            return None

